var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"큭! 아무리 공격해도 사라지질 않아!","JPN":"くっ！　いくら攻撃しても消えない！","ENG":"Ugh! These things just won't go away, no matter how much I attack!","TWN":"咳！再怎麼攻擊也打不掉！"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"이 꿈틀거리는 것들은 대체 뭐야?!","JPN":"このくねくねしているモノは何なの？","ENG":"What are these wriggly things anyway?","TWN":"這些在蠕動的怪東西到底是什麼？！"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"이건...... 아트 디렉터님의 분신이에요.","JPN":"これは……アートディレクターさんの分身です。","ENG":"These are... part of the Art Director's body.","TWN":"這是… 美術局長的分身。"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"아마 집요하게 달려드는 걸 보면, 언니에게 흥미가 생긴 걸지도......","JPN":"ここまでしつこく襲いかかってくるってことは、お姉ちゃんに興味がわいたのかも……","ENG":"The way they just keep coming at you suggests that she's taken an interest in you...","TWN":"看它執意的一直撲過來，也許是對姐姐產生了興趣……"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"흥미....... 라고?","JPN":"興味……って？","ENG":"Interested... in me?","TWN":" 興趣……？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"당신의 기운이 처음 느껴질 때부터 쭉 예의주시해왔어요.","JPN":"あなたのオーラを初めて感じた時からずっと注視していました。","ENG":"We've monitored you closely ever since we could sense your presence.","TWN":"從第一次感受到你的氣息時，我就開始一直密切關注著你。"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"당신은 우리와는 완전히 다른 사고와 지식을 가지고 있군요?","JPN":"あなたは我々とはまったく違う思考と知識を持っていますね？","ENG":"Your reasoning and knowledge are completely different from ours, aren't they?","TWN":"你擁有和我們完全不同的思考和知識呢？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"그 머릿속에 들어있는 독특한 화풍들은 우리 것으로 만들기에 충분히 매력적이에요.","JPN":"その頭の中に入っている独特な画風は、我々のものにしたいほど十分魅力的です。","ENG":"Those unique art styles in your head are appealing enough to make our own.","TWN":"將你腦中的獨特畫風，製作並成為我們自己的，真是非常的有魅力呢。"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","text":{"KOREA":"당신은......?","JPN":"あなたは……？","ENG":"You're…?","TWN":"你是……？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"아트 디렉터님!","JPN":"アートディレクターさん！","ENG":"Art Director!","TWN":"美術局長大人！"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","text":{"KOREA":"저 사람이 아트 디렉터라고? 몸에서 이상한 게 자라고 있는데?","JPN":"あの人がアートディレクター？　身体から変なモノが生えてるけど？","ENG":"That's the Art Director? With all that stuff growing out of her body?","TWN":"那個人就是美術局長？在身上長了奇怪的東西呢？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"아트 디렉터님은...... 이미 한 번 나이트워커가 된 적이 있던 분이에요.","JPN":"アートディレクターさんは……すでに一度ナイトウォーカーになっているんです。","ENG":"The Art Director... She was once a Night Worker herself.","TWN":"美術局長是個…… 曾經變成過夜行者一次的人。"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"하지만 야근에 완전히 침식해 이성을 잃지 않고, 오히려 그 힘을 자기 것으로 흡수한 케이스죠.","JPN":"でも、残業に完全に侵食されても理性を失わず、むしろその力を自分のものとして吸収した珍しいケースです。","ENG":"But instead of giving in to the dark energy of overtime, she absorbed its powers as her own.","TWN":"因爲加班被夜行者完全侵蝕後，不但沒有失去理性，反而吸收成自己的力量。"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","text":{"KOREA":"나이트워커의 힘을...... 자신이 흡수했다고?","JPN":"ナイトウォーカーの力を……自分に吸収した？","ENG":"She absorbed... the Night Worker's power?","TWN":"將夜行者的力量…… 吸收成自己的？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"당신처럼 흥미로운 데이터는 처음 봤어요.","JPN":"あなたのような興味深いデータは初めてです。","ENG":"We've never seen data so curiously interesting as yours.","TWN":"我第一次看像你這樣有趣的數據呢。"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"자, 두려워 말고 저희와 함께 해요.","JPN":"さあ、恐れる必要はありません。我々と一緒になりましょう。","ENG":"Come, join us. There's nothing to be afraid of.","TWN":"來，不要害怕，和我們一起吧。"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"이 계약서에 사인을 하고, 우리 게임과 하나가 되는 거예요.","JPN":"この契約書にサインをして、我が社のゲームと一つになるのです。","ENG":"Sign this contract and become one with our game.","TWN":"在這個契約書上簽個名，跟我們的遊戲合為一體吧。"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"계약서......?","JPN":"契約書？","ENG":"Contract...?","TWN":"契約書……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_20"},{"id":"L24_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"우와, 연봉 액수가 0이 몇 자리야?","JPN":"うわあ、年俸額の桁が……！　0が一体何個あるの？","ENG":"Whoa, how many zeros are in this annual salary figure?","TWN":"哇啊，年薪金額到底有多少 0 啊？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"그, 근무조건은 어떤데? 사인은 여기다가 하면 돼?","JPN":"き、勤務条件はどうなの？　サインはここにすればいい？","ENG":"D-do I get any other perks? Where do I sign? Here?","TWN":"工、工作條件如何？在這裡簽名就好嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"정신을 잃으면 안돼요, 언니! 그건 무기한 야근에 동의하는 종신계약서라고요!","JPN":"しっかりしてください、お姉ちゃん！　それは無制限残業に同意する終身契約書なんです！","ENG":"Snap out of it! That's a lifetime contract agreeing to unlimited overtime!","TWN":"不能失去理性，姐姐！同意這種無限加班的契約簡直就像終身雇傭呢！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_NULL","text":{"KOREA":"......!","JPN":"……！","ENG":"......!","TWN":" ……！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_20"},{"id":"L29_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","text":{"KOREA":"크윽! 하마터면 당할 뻔했군.","JPN":"くっ！　やられるところだった。","ENG":"Ugh! I almost fell for it!","TWN":"咳呃！差點失手鑄成大錯了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","text":{"KOREA":"제안은 고맙지만 난 돌아가야 할 곳이 있어서 말이야.","JPN":"提案はありがたいけど、私には帰るべき場所があるの。","ENG":"I appreciate the offer, but I've got somewhere to be.","TWN":"謝謝你的提議，但我想要回家。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_MI_NA_NPC_FOOLSDAY_LITTLE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"......안타깝게도.","JPN":"……残念です。","ENG":"...How unfortunate.","TWN":" ……真可惜。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"하지만 우린 지금 새로운 지식에 굶주려 있어요.","JPN":"しかし我々は新しい知識に飢えています。","ENG":"But we are currently hungry for new knowledge.","TWN":"但是，我們現在對新的知識非常渴望。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"그렇게 거부한다면, 강제로라도 당신을 우리의 양분으로 삼겠어요.","JPN":"そこまで拒否するなら、無理やりにでもあなたを我々の養分にしましょう。","ENG":"If you must refuse, we'll have to consume you by force.","TWN":"如果那樣拒絕，即使強迫，我也要把你當作我們的養分。"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LARA_NPC_DILIVER_NULL","text":{"KOREA":"배달 왔습니다! 족발 시키셨죠?","JPN":"出前の配達です！　チャーシューのご注文でお間違いないですね？","ENG":"Delivery! You ordered pettitoes, right?","TWN":"外送到了！點了豬腳對吧？"},"stage":{"bg":"GAUNTLET","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LARA_NPC_DILIVER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"SHADOW_NPC_FOOLSDAY_NULL","text":{"KOREA":"아......","JPN":"あ……","ENG":"Uh...","TWN":"啊……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHADOW_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LARA_NPC_DILIVER_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};